from pwn import *
elf=ELF('/home/ctfplayer/ctf_files/maze_public')
text=elf.section('.text'); base=elf.get_section_by_name('.text').header.sh_addr
pat=bytes.fromhex('488d05f9ffffffc600c349ffc78a0748ffc73c0a')
nodes=[]
for i in range(len(text)-len(pat)):
    if text[i:i+len(pat)]==pat: nodes.append(base+i)
S=set(nodes)
start=0x403eb6
moves={1:(-2,1),2:(-1,2),3:(1,2),4:(2,1),5:(2,-1),6:(1,-2),7:(-1,-2),8:(-2,-1)}
step=0xcd
adj={a:{} for a in nodes}
for a in nodes:
    for d,(dx,dy) in moves.items():
        b=a+((dx*12+dy)*step)
        if b in S:
            adj[a][d]=b
# find any walk len64
L=64
from functools import lru_cache
@lru_cache(None)
def dfs(a,l):
    if l==0:return ''
    for d,b in adj[a].items():
        r=dfs(b,l-1)
        if r is not None:
            return str(d)+r
    return None
path=dfs(start,L)
print('path',path[:80],len(path) if path else None)
# test
if path:
    p=process('/home/ctfplayer/ctf_files/maze_public')
    p.recvuntil(b'input: \n')
    p.send((path+'\n').encode())
    print(p.recvall(timeout=1))
